import { describe, expect, it } from 'vitest';

import {
  admitMeshAuthentic,
  admittedToken,
  detectedAbove,
  forged,
  genuine,
  watermarkThreshold,
  WatermarkMeshIdentityMaster,
  weak,
  type RecoveredWatermark,
} from '../src/acoustic-watermark-mesh-identity';

describe('admittedToken (mirrors admittedTokenB)', () => {
  it('admits the canonical protocol69 marker and the issued set', () => {
    expect(admittedToken(69)).toBe(true);
    expect(admittedToken(66)).toBe(true);
    expect(admittedToken(660)).toBe(true);
  });

  it('rejects tokens the mesh never issued', () => {
    expect(admittedToken(7)).toBe(false);
    expect(admittedToken(0)).toBe(false);
    expect(admittedToken(68)).toBe(false);
    expect(admittedToken(70)).toBe(false);
  });
});

describe('detectedAbove (mirrors DetectedAbove)', () => {
  it('clears the gate when correlation meets or exceeds the threshold', () => {
    expect(detectedAbove(50, genuine)).toBe(true);
    expect(detectedAbove(50, { token: 69, correlation: 50 })).toBe(true);
  });

  it('does not clear the gate at noise-level correlation', () => {
    expect(detectedAbove(50, weak)).toBe(false);
    expect(detectedAbove(50, { token: 69, correlation: 49 })).toBe(false);
  });
});

describe('promotion check: admitMeshAuthentic', () => {
  it('admits a detected, admitted-token recovery (genuine)', () => {
    const a = admitMeshAuthentic(genuine, { threshold: watermarkThreshold });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.correlationCleared).toBe(true);
    expect(a.tokenAdmitted).toBe(true);
  });

  it('withholds on a forged token even at strong correlation', () => {
    const a = admitMeshAuthentic(forged, { threshold: watermarkThreshold });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('forged_token');
    expect(a.correlationCleared).toBe(true);
    expect(a.tokenAdmitted).toBe(false);
  });

  it('withholds on weak correlation even with an admitted token', () => {
    const a = admitMeshAuthentic(weak, { threshold: watermarkThreshold });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('weak_correlation');
    expect(a.correlationCleared).toBe(false);
    expect(a.tokenAdmitted).toBe(true);
  });

  it('reports weak_correlation first when both gates fail (forged + weak)', () => {
    const both: RecoveredWatermark = { token: 7, correlation: 10 };
    const a = admitMeshAuthentic(both, { threshold: watermarkThreshold });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('weak_correlation');
  });

  it('honors the threshold boundary (correlation == threshold is admitted)', () => {
    const edge: RecoveredWatermark = { token: 69, correlation: 50 };
    expect(admitMeshAuthentic(edge, { threshold: 50 }).outcome).toBe(
      'claim_admitted',
    );
  });
});

describe('hard negative: same audible content, different authenticity', () => {
  it('genuine and forged carry identical correlation but split on provenance', () => {
    expect(genuine.correlation).toBe(forged.correlation);
    expect(
      admitMeshAuthentic(genuine, { threshold: watermarkThreshold }).outcome,
    ).toBe('claim_admitted');
    expect(
      admitMeshAuthentic(forged, { threshold: watermarkThreshold }).outcome,
    ).toBe('claim_withheld');
  });
});

describe('WatermarkMeshIdentityMaster (mirrors watermark_mesh_identity_master)', () => {
  it('every boundary witness holds', () => {
    expect(WatermarkMeshIdentityMaster.genuineTokenAdmitted).toBe(true);
    expect(WatermarkMeshIdentityMaster.forgedTokenNotAdmitted).toBe(true);
    expect(WatermarkMeshIdentityMaster.genuineAdmitted).toBe(true);
    expect(WatermarkMeshIdentityMaster.forgedTokenRejected).toBe(true);
    expect(WatermarkMeshIdentityMaster.forgedRejected).toBe(true);
    expect(WatermarkMeshIdentityMaster.weakCorrelationRejected).toBe(true);
    expect(WatermarkMeshIdentityMaster.weakRejected).toBe(true);
    expect(WatermarkMeshIdentityMaster.authenticityDistinguished).toBe(true);
  });

  it('uses the Lean fixture numbers (threshold 50, tokens 69/7, corr 90/10)', () => {
    expect(watermarkThreshold).toBe(50);
    expect(genuine).toEqual({ token: 69, correlation: 90 });
    expect(forged).toEqual({ token: 7, correlation: 90 });
    expect(weak).toEqual({ token: 69, correlation: 10 });
  });
});
